import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput); // Sanitize user input

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println("<html><body>");
        out.println("<p>User Input: " + sanitizedInput + "</p>"); // Display sanitized input
        out.println("</body></html>");
    }

    private String sanitizeInput(String input) {
        if (input == null) {
            return "";
        }

        // Replace characters that could be interpreted as HTML tags
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("&", "&amp;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
